// Script Continued Below
// STRY0014064
updateChildtoParent();
updateParentTasktoTopTask();

function updateChildtoParent(){
	var gr = new GlideRecord("x_153465_discovert_route_task_instance");
	gr.addNotNullQuery('child_route_template');
	gr.query();
	while(gr.next()){
		gr.u_parent_template = gr.child_route_template;
		gr.child_route_template = '';
		gr.update();
	}
}

function updateParentTasktoTopTask(){
	var gr = new GlideRecord("x_153465_discovert_discover_routing_runtime");
	gr.addNotNullQuery('parent_task');
	gr.query();
	while(gr.next()){
		gr.u_top_task = gr.parent_task;
		gr.parent_task = '';
		gr.update();
	}
}
